import { isUuidV7, prototype } from '@sovereignbase/utils'
import { transformSnapshotEntryToStateEntry } from '../../../.helpers/index.js'
import type { CRMapSnapshot, CRMapState } from '../../../.types/index.js'

/**
 * Creates a local CRMap replica from an optional snapshot.
 *
 * Invalid snapshot records are ignored. Accepted tombstones are materialized
 * first, then live entries are cloned into the replica. Duplicate key
 * contenders use a minimal deterministic tie-break: a direct descendant wins,
 * the same UUID can advance with a larger predecessor, and otherwise the larger
 * UUIDv7 wins.
 *
 * @param snapshot Optional serialized CRMap state.
 * @returns A hydrated CRMap replica.
 *
 * Time complexity: O(v + t + c), worst case O(v + t + c)
 * - v = snapshot value entry count
 * - t = snapshot tombstone count
 * - c = cloned value payload size across accepted entries
 *
 * Space complexity: O(v + t + c)
 */
export function __create<T>(
  snapshot?: CRMapSnapshot<string, T>
): CRMapState<string, T> {
  const crMapReplica: CRMapState<string, T> = {
    values: new Map(),
    relations: new Map(),
    tombstones: new Set(),
    predecessors: new Set(),
  }
  if (!snapshot || prototype(snapshot) !== 'record') return crMapReplica

  if (
    Object.hasOwn(snapshot, 'tombstones') &&
    Array.isArray(snapshot.tombstones)
  ) {
    for (const tombstone of snapshot.tombstones) {
      if (!isUuidV7(tombstone) || crMapReplica.tombstones.has(tombstone))
        continue
      crMapReplica.tombstones.add(tombstone)
    }
  }

  if (!Object.hasOwn(snapshot, 'values') || !Array.isArray(snapshot.values))
    return crMapReplica

  for (const snapshotEntry of snapshot.values) {
    if (prototype(snapshotEntry) !== 'record') continue
    if (crMapReplica.tombstones.has(snapshotEntry.uuidv7)) continue
    const stateEntry = transformSnapshotEntryToStateEntry<T>(snapshotEntry)
    if (!stateEntry) continue

    const currentEntry = crMapReplica.values.get(stateEntry.value.key)
    if (
      currentEntry &&
      currentEntry.uuidv7 === stateEntry.uuidv7 &&
      currentEntry.predecessor >= stateEntry.predecessor
    )
      continue
    if (
      currentEntry &&
      currentEntry.uuidv7 !== stateEntry.uuidv7 &&
      currentEntry.uuidv7 !== stateEntry.predecessor &&
      currentEntry.uuidv7 >= stateEntry.uuidv7
    )
      continue
    if (currentEntry) {
      crMapReplica.relations.delete(currentEntry.uuidv7)
      crMapReplica.predecessors.delete(currentEntry.predecessor)
    }
    crMapReplica.relations.set(stateEntry.uuidv7, stateEntry.value.key)
    crMapReplica.values.set(stateEntry.value.key, stateEntry)
    crMapReplica.predecessors.add(stateEntry.predecessor)
  }
  return crMapReplica
}
import { prototype, isUuidV7, safeStructuredClone } from '@sovereignbase/utils'
import type { CRMapSnapshotEntry, CRMapStateEntry } from '../../.types/index.js'

export function transformSnapshotEntryToStateEntry<T>(
  snapshotEntry: CRMapSnapshotEntry<string, T>
): CRMapStateEntry<string, T> | false {
  if (
    prototype(snapshotEntry) !== 'record' ||
    !Object.hasOwn(snapshotEntry, 'value') ||
    !isUuidV7(snapshotEntry.uuidv7) ||
    !isUuidV7(snapshotEntry.predecessor)
  )
    return false

  const { key, value } = snapshotEntry.value
  if (!key || typeof key !== 'string') return false
  const [cloned, copiedValue] = safeStructuredClone(value)
  if (!cloned) return false

  return {
    uuidv7: snapshotEntry.uuidv7,
    value: { key, value: copiedValue },
    predecessor: snapshotEntry.predecessor,
  }
}
import { prototype, isUuidV7, safeStructuredClone } from '@sovereignbase/utils'
import type { CRMapSnapshotEntry, CRMapStateEntry } from '../../.types/index.js'

export function transformStateEntryToSnapshotEntry<T>(
  stateEntry: CRMapStateEntry<string, T>
): CRMapSnapshotEntry<string, T> {
  return {
    uuidv7: stateEntry.uuidv7,
    value: {
      key: stateEntry.value.key,
      value: structuredClone(stateEntry.value.value),
    },
    predecessor: stateEntry.predecessor,
  }
}
import type { CRMapState } from '../../../.types/index.js'

/**
 * Reads the current visible value for a key.
 *
 * Successful reads return a detached structured clone of the stored value, so
 * mutating the returned object does not mutate the replica. Missing keys
 * resolve to `undefined`.
 *
 * @param key Target key in the live map.
 * @param crMapReplica Replica to read from.
 * @returns A detached copy of the current value, or `undefined` when the key
 * is absent.
 *
 * Time complexity: O(c), worst case O(c)
 * - c = cloned value payload size
 *
 * Space complexity: O(c)
 */
export function __read<T>(
  key: string,
  crMapReplica: CRMapState<string, T>
): T | undefined {
  return structuredClone(crMapReplica.values.get(key)?.value.value)
}
import { safeStructuredClone } from '@sovereignbase/utils'
import type {
  CRMapChange,
  CRMapDelta,
  CRMapState,
} from '../../../.types/index.js'
import { v7 as uuidv7 } from 'uuid'

/**
 * Overwrites the current visible value for a key and emits the resulting delta.
 *
 * The incoming value is cloned first, then written as the new winning state
 * entry for `key`. The predecessor entry is tombstoned so the returned delta is
 * ready for gossip. Internal helper indexes are updated to keep merge and
 * garbage collection logic coherent.
 *
 * @param key Target key to overwrite.
 * @param value Next visible value for the key.
 * @param crMapReplica Replica to mutate.
 * @returns The local visible change and serialized delta, or `false` when the
 * key is invalid or the value cannot be cloned.
 *
 * Time complexity: O(c), worst case O(c)
 * - c = cloned value payload size
 *
 * Space complexity: O(c)
 */
export function __update<T>(
  key: string,
  value: T,
  crMapReplica: CRMapState<string, T>
): { delta: CRMapDelta<string, T>; change: CRMapChange<string, T> } | false {
  if (typeof key !== 'string') return false

  const [cloned, copiedValue] = safeStructuredClone(value)
  if (!cloned) return false

  const oldEntry = crMapReplica.values.get(key)
  const predecessor = oldEntry ? oldEntry.uuidv7 : uuidv7()
  const entry = {
    uuidv7: uuidv7(),
    value: { key, value: copiedValue },
    predecessor,
  }
  if (oldEntry) {
    crMapReplica.relations.delete(oldEntry.uuidv7)
    crMapReplica.predecessors.delete(oldEntry.predecessor)
  }
  crMapReplica.values.set(key, entry)
  crMapReplica.relations.set(entry.uuidv7, key)
  crMapReplica.predecessors.add(predecessor)
  crMapReplica.tombstones.add(predecessor)
  const delta: CRMapDelta<string, T> = {
    values: [
      {
        uuidv7: entry.uuidv7,
        value: { key, value: copiedValue },
        predecessor,
      },
    ],
    tombstones: [predecessor],
  }
  const change: CRMapChange<string, T> = {}
  change[key] = structuredClone(copiedValue) //detached

  return { delta, change }
}
import type {
  CRMapChange,
  CRMapDelta,
  CRMapState,
} from '../../../.types/index.js'

/**
 * Deletes one key or every live key from the replica.
 *
 * A keyed delete removes one visible entry. When no key is specified, every
 * live entry is removed. Removed UUIDv7 identifiers are recorded as tombstones
 * so the returned delta can be merged by peers. Internal helper indexes are
 * updated at the same time. Missing keys resolve to `false` without mutating
 * the replica.
 *
 * @param key Target key to delete.
 * @param crMapReplica Replica to mutate.
 * @returns A tombstone-only delta plus a visible delete projection, or `false`
 * when no deletion occurred.
 *
 * Time complexity: O(1) for keyed deletes, O(k) for full deletes
 * Space complexity: O(1) for keyed deletes, O(k) for full deletes
 */
export function __delete<T>(
  crMapReplica: CRMapState<string, T>,
  key?: string
): { delta: CRMapDelta<string, T>; change: CRMapChange<string, T> } | false
export function __delete<T>(
  key: string,
  crMapReplica: CRMapState<string, T>
): { delta: CRMapDelta<string, T>; change: CRMapChange<string, T> } | false
export function __delete<T>(
  keyOrReplica: string | CRMapState<string, T>,
  crMapReplicaOrKey?: CRMapState<string, T> | string
): { delta: CRMapDelta<string, T>; change: CRMapChange<string, T> } | false {
  const crMapReplica =
    typeof keyOrReplica === 'string'
      ? (crMapReplicaOrKey as CRMapState<string, T> | undefined)
      : keyOrReplica
  const key =
    typeof keyOrReplica === 'string'
      ? keyOrReplica
      : typeof crMapReplicaOrKey === 'string'
        ? crMapReplicaOrKey
        : undefined
  if (!crMapReplica) return false

  if (key !== undefined) {
    const entry = crMapReplica.values.get(key)
    if (!entry) return false

    crMapReplica.tombstones.add(entry.uuidv7)
    crMapReplica.values.delete(key)
    crMapReplica.relations.delete(entry.uuidv7)
    crMapReplica.predecessors.delete(entry.predecessor)
    const delta: CRMapDelta<string, T> = {
      tombstones: [entry.uuidv7],
    }
    const change: CRMapChange<string, T> = { [key]: undefined }
    return { delta, change }
  }

  if (crMapReplica.values.size === 0) return false

  const delta: CRMapDelta<string, T> = { tombstones: [] }
  const change: CRMapChange<string, T> = {}
  for (const [liveKey, entry] of crMapReplica.values.entries()) {
    crMapReplica.tombstones.add(entry.uuidv7)
    delta.tombstones!.push(entry.uuidv7)
    change[liveKey] = undefined
  }
  crMapReplica.values.clear()
  crMapReplica.relations.clear()
  crMapReplica.predecessors.clear()

  return { delta, change }
}
import { isUuidV7, prototype } from '@sovereignbase/utils'
import type {
  CRMapDelta,
  CRMapChange,
  CRMapState,
} from '../../../.types/index.js'
import {
  transformSnapshotEntryToStateEntry,
  transformStateEntryToSnapshotEntry,
} from '../../../.helpers/index.js'

/**
 * Merges an incoming delta into the current replica.
 *
 * Accepted tombstones remove visible keys immediately. Value contenders for a
 * known key follow the same conflict model as `CRStruct`: same UUIDs can
 * advance via a larger predecessor, direct descendants win, and otherwise the
 * larger UUIDv7 wins. When local state already dominates an incoming contender,
 * the function emits a reply delta.
 *
 * @param crMapDelta Incoming partial snapshot projection.
 * @param crMapReplica Local replica state.
 * @returns The visible change projection and optional reply delta, or `false`
 * when the input is invalid or produces no effect.
 */
export function __merge<T>(
  crMapDelta: CRMapDelta<string, T>,
  crMapReplica: CRMapState<string, T>
): { change: CRMapChange<string, T>; delta: CRMapDelta<string, T> } | false {
  if (!crMapDelta || prototype(crMapDelta) !== 'record') return false

  const change: CRMapChange<string, T> = {}
  const delta: CRMapDelta<string, T> = {}
  let hasChange = false
  let hasDelta = false

  if (
    Object.hasOwn(crMapDelta, 'tombstones') &&
    Array.isArray(crMapDelta.tombstones)
  ) {
    for (const tombstone of crMapDelta.tombstones) {
      if (!isUuidV7(tombstone) || crMapReplica.tombstones.has(tombstone))
        continue
      crMapReplica.tombstones.add(tombstone)
      const live = crMapReplica.relations.get(tombstone)
      if (!live) continue
      const currentEntry = crMapReplica.values.get(live)
      if (!currentEntry || currentEntry.uuidv7 !== tombstone) {
        crMapReplica.relations.delete(tombstone)
        continue
      }
      crMapReplica.values.delete(live)
      crMapReplica.relations.delete(tombstone)
      crMapReplica.predecessors.delete(currentEntry.predecessor)
      change[live] = undefined
      hasChange = true
    }
  }

  if (!Object.hasOwn(crMapDelta, 'values') || !Array.isArray(crMapDelta.values))
    return hasChange ? { change, delta } : false

  for (const snapshotEntry of crMapDelta.values) {
    if (prototype(snapshotEntry) !== 'record') continue
    if (crMapReplica.tombstones.has(snapshotEntry.uuidv7)) continue
    const contender = transformSnapshotEntryToStateEntry<T>(snapshotEntry)
    if (!contender) continue

    const currentEntry = crMapReplica.values.get(contender.value.key)
    if (!currentEntry) {
      crMapReplica.values.set(contender.value.key, contender)
      crMapReplica.relations.set(contender.uuidv7, contender.value.key)
      crMapReplica.predecessors.add(contender.predecessor)
      crMapReplica.tombstones.add(contender.predecessor)
      change[contender.value.key] = structuredClone(contender.value.value)
      hasChange = true
      continue
    }

    if (currentEntry.uuidv7 === contender.uuidv7) {
      if (currentEntry.predecessor < contender.predecessor) {
        crMapReplica.predecessors.delete(currentEntry.predecessor)
        currentEntry.value = contender.value
        currentEntry.predecessor = contender.predecessor
        crMapReplica.predecessors.add(contender.predecessor)
        crMapReplica.tombstones.add(contender.predecessor)
        change[contender.value.key] = structuredClone(contender.value.value)
        hasChange = true
      } else {
        if (!delta.values) delta.values = []
        delta.values.push(transformStateEntryToSnapshotEntry(currentEntry))
        hasDelta = true
      }
      continue
    }

    if (
      currentEntry.uuidv7 === contender.predecessor ||
      crMapReplica.tombstones.has(currentEntry.uuidv7) ||
      contender.uuidv7 > currentEntry.uuidv7
    ) {
      crMapReplica.tombstones.add(contender.predecessor)
      crMapReplica.tombstones.add(currentEntry.uuidv7)
      crMapReplica.relations.delete(currentEntry.uuidv7)
      crMapReplica.predecessors.delete(currentEntry.predecessor)
      crMapReplica.values.set(contender.value.key, contender)
      crMapReplica.relations.set(contender.uuidv7, contender.value.key)
      crMapReplica.predecessors.add(contender.predecessor)
      change[contender.value.key] = structuredClone(contender.value.value)
      hasChange = true
      continue
    }

    crMapReplica.tombstones.add(contender.uuidv7)
    if (!delta.tombstones) delta.tombstones = []
    delta.tombstones.push(contender.uuidv7)
    if (!delta.values) delta.values = []
    delta.values.push(transformStateEntryToSnapshotEntry(currentEntry))
    hasDelta = true
  }

  if (!hasChange && !hasDelta) return false

  return { change, delta }
}
import { isUuidV7 } from '@sovereignbase/utils'
import type { CRMapAck, CRMapState } from '../../../.types/index.js'

/**
 * Emits the current acknowledgement frontier for the replica.
 *
 * The frontier is the largest valid tombstone identifier currently retained by
 * the replica. Empty replicas acknowledge `''`.
 *
 * @param crMapReplica Replica to summarize.
 * @returns The largest retained tombstone identifier, or `''` when none exist.
 */
export function __acknowledge<T>(
  crMapReplica: CRMapState<string, T>
): CRMapAck {
  let largest: CRMapAck = ''
  for (const tombstone of crMapReplica.tombstones.values()) {
    if (!isUuidV7(tombstone) || tombstone < largest) continue
    largest = tombstone
  }
  return largest
}
import { isUuidV7 } from '@sovereignbase/utils'
import type { CRMapAck, CRMapState } from '../../../.types/index.js'

/**
 * Removes tombstones that every provided frontier has acknowledged.
 *
 * The smallest valid acknowledgement is selected first. Tombstones at or below
 * that frontier are removed while preserving identifiers still referenced as
 * live predecessors.
 *
 * @param frontiers A collection of acknowledgement frontiers.
 * @param crMapReplica Replica to compact.
 */
export function __garbageCollect<T>(
  frontiers: Array<CRMapAck>,
  crMapReplica: CRMapState<string, T>
): void {
  if (!Array.isArray(frontiers) || frontiers.length < 1) return
  let smallest = ''
  for (const frontier of frontiers) {
    if (!isUuidV7(frontier)) continue
    if (smallest !== '' && smallest <= frontier) continue
    smallest = frontier
  }
  if (smallest === '') return

  crMapReplica.tombstones.forEach((tombstone, _, tombstones) => {
    if (tombstone > smallest || crMapReplica.predecessors.has(tombstone))
      return
    tombstones.delete(tombstone)
  })
}
import { transformStateEntryToSnapshotEntry } from '../../../.helpers/index.js'
import type { CRMapSnapshot, CRMapState } from '../../../.types/index.js'

/**
 * Serializes the current replica state into a snapshot projection.
 *
 * Each visible entry is converted to its serializable form and all retained
 * tombstones are emitted.
 *
 * @param crMapReplica Replica to serialize.
 * @returns A full snapshot suitable for hydration or transport.
 */
export function __snapshot<T>(
  crMapReplica: CRMapState<string, T>
): CRMapSnapshot<string, T> {
  const out: CRMapSnapshot<string, T> = {
    values: [],
    tombstones: Array.from(crMapReplica.tombstones),
  }
  for (const stateEntry of crMapReplica.values.values()) {
    out.values.push(transformStateEntryToSnapshotEntry(stateEntry))
  }
  return out
}
import type {
  CRMapAck,
  CRMapChange,
  CRMapDelta,
  CRMapEventMap,
  CRMapSnapshot,
  CRMapState,
} from '../.types/index.js'
import { __create, __read, __update, __delete } from '../core/crud/index.js'
import {
  __merge,
  __acknowledge,
  __garbageCollect,
  __snapshot,
} from '../core/mags/index.js'

/**
 * A convergent replicated map keyed by strings.
 *
 * Reads, iteration, and collection views expose detached copies of the current
 * live projection. Local mutations emit `delta` and `change` events. Merges may
 * emit `change`, `delta`, or both depending on whether the incoming state
 * changes the visible projection or requires a reply delta.
 *
 * @typeParam T - The value type stored in the map.
 */
export class CRMap<T> {
  declare private readonly state: CRMapState<string, T>
  declare private readonly eventTarget: EventTarget

  /**
   * Creates a replicated map from an optional serializable snapshot.
   *
   * @param snapshot - A previously emitted CRMap snapshot.
   */
  constructor(snapshot?: CRMapSnapshot<string, T>) {
    Object.defineProperties(this, {
      state: {
        value: __create<T>(snapshot),
        enumerable: false,
        configurable: false,
        writable: false,
      },
      eventTarget: {
        value: new EventTarget(),
        enumerable: false,
        configurable: false,
        writable: false,
      },
    })
  }

  /**
   * The current number of live keys.
   */
  get size(): number {
    return this.state.values.size
  }

  /**
   * Reads the current visible value for a key.
   *
   * @param key - Target key in the live map.
   * @returns A detached copy of the value, or `undefined` when the key is absent.
   */
  get(key: string): T | undefined {
    return __read<T>(key, this.state)
  }

  /**
   * Checks whether a key currently exists in the live projection.
   *
   * @param key - Key to check.
   * @returns `true` when the key is currently visible.
   */
  has(key: string): boolean {
    return this.state.values.has(key)
  }

  /**
   * Overwrites the visible value for a key.
   *
   * @param key - Key to write.
   * @param value - Next visible value for the key.
   */
  set(key: string, value: T): void {
    const result = __update<T>(key, value, this.state)
    if (!result) return
    this.dispatchDelta(result.delta)
    this.dispatchChange(result.change)
  }

  /**
   * Deletes one visible key.
   *
   * @param key - Key to remove.
   */
  delete(key: string): void {
    const result = __delete(this.state, key)
    if (!result) return
    this.dispatchDelta(result.delta)
    this.dispatchChange(result.change)
  }

  /**
   * Deletes every visible key.
   */
  clear(): void {
    const result = __delete(this.state)
    if (!result) return
    this.dispatchDelta(result.delta)
    this.dispatchChange(result.change)
  }

  /**
   * Returns the current live keys.
   *
   * @returns The current keys in map iteration order.
   */
  keys(): Array<string> {
    return Array.from(this.state.values.keys())
  }

  /**
   * Returns detached copies of the current live values.
   *
   * @returns The current values in map iteration order.
   */
  values(): Array<T> {
    return Array.from(this.state.values.values(), (entry) =>
      structuredClone(entry.value.value)
    )
  }

  /**
   * Returns detached key-value pairs for the current live projection.
   *
   * @returns The current entries in map iteration order.
   */
  entries(): Array<[string, T]> {
    return Array.from(this.state.values.values(), (entry) => [
      entry.value.key,
      structuredClone(entry.value.value),
    ])
  }

  /**
   * Applies a remote or local delta to the replica state.
   *
   * @param delta - The partial serialized map state to merge.
   */
  merge(delta: CRMapDelta<string, T>): void {
    const result = __merge<T>(delta, this.state)
    if (!result) return
    this.dispatchDelta(result.delta)
    this.dispatchChange(result.change)
  }

  /**
   * Emits the current acknowledgement frontier.
   */
  acknowledge(): void {
    const ack = __acknowledge<T>(this.state)
    if (!ack) return
    void this.eventTarget.dispatchEvent(new CustomEvent('ack', { detail: ack }))
  }

  /**
   * Removes tombstones that every provided frontier has acknowledged.
   *
   * @param frontiers - Replica acknowledgement frontiers.
   */
  garbageCollect(frontiers: Array<CRMapAck>): void {
    void __garbageCollect<T>(frontiers, this.state)
  }

  /**
   * Emits the current serializable map snapshot.
   */
  snapshot(): void {
    const snapshot = __snapshot<T>(this.state)
    void this.eventTarget.dispatchEvent(
      new CustomEvent('snapshot', { detail: snapshot })
    )
  }

  /**
   * Registers an event listener.
   *
   * @param type - The event type to listen for.
   * @param listener - The listener to register.
   * @param options - Listener registration options.
   */
  addEventListener<K extends keyof CRMapEventMap<string, T>>(
    type: K,
    listener: EventListenerOrEventListenerObject | null,
    options?: boolean | AddEventListenerOptions
  ): void {
    this.eventTarget.addEventListener(type, listener, options)
  }

  /**
   * Removes an event listener.
   *
   * @param type - The event type to stop listening for.
   * @param listener - The listener to remove.
   * @param options - Listener removal options.
   */
  removeEventListener<K extends keyof CRMapEventMap<string, T>>(
    type: K,
    listener: EventListenerOrEventListenerObject | null,
    options?: boolean | EventListenerOptions
  ): void {
    this.eventTarget.removeEventListener(type, listener, options)
  }

  /**
   * Returns a serializable snapshot representation of this map.
   *
   * Called automatically by `JSON.stringify`.
   */
  toJSON(): CRMapSnapshot<string, T> {
    return __snapshot<T>(this.state)
  }

  /**
   * Returns this map as a JSON string.
   */
  toString(): string {
    return JSON.stringify(this)
  }

  /**
   * Returns the Node.js console inspection representation.
   */
  [Symbol.for('nodejs.util.inspect.custom')](): CRMapSnapshot<string, T> {
    return this.toJSON()
  }

  /**
   * Returns the Deno console inspection representation.
   */
  [Symbol.for('Deno.customInspect')](): CRMapSnapshot<string, T> {
    return this.toJSON()
  }

  /**
   * Iterates over detached copies of the current live entries.
   */
  *[Symbol.iterator](): IterableIterator<[string, T]> {
    for (const entry of this.state.values.values()) {
      yield [entry.value.key, structuredClone(entry.value.value)]
    }
  }

  /**
   * Calls a function once for each live entry copy in map iteration order.
   *
   * Callback values are detached copies, so mutating them does not mutate the
   * replica.
   *
   * @param callback - Function to call for each key-value pair.
   * @param thisArg - Optional `this` value for the callback.
   */
  forEach(
    callback: (value: T, key: string, map: this) => void,
    thisArg?: unknown
  ): void {
    for (const [key, value] of this) {
      callback.call(thisArg, value, key, this)
    }
  }

  private dispatchDelta(delta: CRMapDelta<string, T>): void {
    if ((delta.values?.length ?? 0) + (delta.tombstones?.length ?? 0) < 1)
      return
    void this.eventTarget.dispatchEvent(
      new CustomEvent('delta', { detail: delta })
    )
  }

  private dispatchChange(change: CRMapChange<string, T>): void {
    if (Object.keys(change).length < 1) return
    void this.eventTarget.dispatchEvent(
      new CustomEvent('change', { detail: change })
    )
  }
}
